#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <cuda_runtime.h>

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

#define OPEN
#define ITERATION

static inline void cuda_check(cudaError_t err, const char *file, int line) {
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA error at %s:%d: %s\n", file, line, cudaGetErrorString(err));
        exit(1);
    }
}

#define CUDA_CHECK(x) cuda_check((x), __FILE__, __LINE__)

void random_matrix(float *I, int rows, int cols);

void usage(int argc, char **argv)
{
    fprintf(stderr, "Usage: %s <rows> <cols> <y1> <y2> <x1> <x2> <no. of threads><lamda> <no. of iter>\n", argv[0]);
    fprintf(stderr, "\t<rows>   - number of rows\n");
    fprintf(stderr, "\t<cols>    - number of cols\n");
    fprintf(stderr, "\t<y1> \t - y1 value of the speckle\n");
    fprintf(stderr, "\t<y2>      - y2 value of the speckle\n");
    fprintf(stderr, "\t<x1>       - x1 value of the speckle\n");
    fprintf(stderr, "\t<x2>       - x2 value of the speckle\n");
    fprintf(stderr, "\t<no. of threads>  - no. of threads\n");
    fprintf(stderr, "\t<lamda>   - lambda (0,1)\n");
    fprintf(stderr, "\t<no. of iter>   - number of iterations\n");

    exit(1);
}

__global__ void srad_cuda_1(
    const float *J,
    float *dN, float *dS, float *dW, float *dE,
    float *c,
    int rows, int cols,
    float q0sqr)
{
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    int i = blockIdx.y * blockDim.y + threadIdx.y;

    if (i < rows && j < cols) {
        int k = i * cols + j;

        int iN = (i == 0) ? 0 : (i - 1);
        int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
        int jW = (j == 0) ? 0 : (j - 1);
        int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

        float Jc = J[k];

        float dNk = J[iN * cols + j] - Jc;
        float dSk = J[iS * cols + j] - Jc;
        float dWk = J[i * cols + jW] - Jc;
        float dEk = J[i * cols + jE] - Jc;

        dN[k] = dNk;
        dS[k] = dSk;
        dW[k] = dWk;
        dE[k] = dEk;

        float G2 = (dNk * dNk + dSk * dSk + dWk * dWk + dEk * dEk) / (Jc * Jc);
        float L = (dNk + dSk + dWk + dEk) / Jc;

        float num = (0.5f * G2) - ((1.0f / 16.0f) * (L * L));
        float den = 1.0f + (0.25f * L);
        float qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
        float ck = 1.0f / (1.0f + den);

        if (ck < 0.0f) ck = 0.0f;
        else if (ck > 1.0f) ck = 1.0f;

        c[k] = ck;
    }
}

__global__ void srad_cuda_2(
    float *J,
    const float *c,
    const float *dN, const float *dS, const float *dW, const float *dE,
    int rows, int cols,
    float lambda)
{
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    int i = blockIdx.y * blockDim.y + threadIdx.y;

    if (i < rows && j < cols) {
        int k = i * cols + j;

        int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
        int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

        float cN = c[k];
        float cS = c[iS * cols + j];
        float cW = c[k];
        float cE = c[i * cols + jE];

        float D = cN * dN[k] + cS * dS[k] + cW * dW[k] + cE * dE[k];
        J[k] = J[k] + 0.25f * lambda * D;
    }
}

int main(int argc, char* argv[])
{
    int rows, cols, size_I, size_R, niter = 10, iter, k;
    float *I, *J, q0sqr, sum, sum2, tmp, meanROI, varROI;
    int r1, r2, c1, c2;
    float lambda;
    int i, j;
    int nthreads;

    if (argc == 10)
    {
        rows = atoi(argv[1]);
        cols = atoi(argv[2]);
        if ((rows % 16 != 0) || (cols % 16 != 0)) {
            fprintf(stderr, "rows and cols must be multiples of 16\n");
            exit(1);
        }
        r1 = atoi(argv[3]);
        r2 = atoi(argv[4]);
        c1 = atoi(argv[5]);
        c2 = atoi(argv[6]);
        nthreads = atoi(argv[7]);
        lambda = (float)atof(argv[8]);
        niter = atoi(argv[9]);
    }
    else {
        usage(argc, argv);
    }

    (void)nthreads;

    size_I = cols * rows;
    size_R = (r2 - r1 + 1) * (c2 - c1 + 1);

    I = (float *)malloc(size_I * sizeof(float));
    J = (float *)malloc(size_I * sizeof(float));

    if (I == NULL || J == NULL) {
        fprintf(stderr, "Host memory allocation failed\n");
        exit(1);
    }

    printf("Randomizing the input matrix\n");

    random_matrix(I, rows, cols);

    for (k = 0; k < size_I; k++) {
        J[k] = expf(I[k]);
    }

    float *d_J = NULL, *d_c = NULL, *d_dN = NULL, *d_dS = NULL, *d_dW = NULL, *d_dE = NULL;
    CUDA_CHECK(cudaMalloc((void **)&d_J,  size_I * sizeof(float)));
    CUDA_CHECK(cudaMalloc((void **)&d_c,  size_I * sizeof(float)));
    CUDA_CHECK(cudaMalloc((void **)&d_dN, size_I * sizeof(float)));
    CUDA_CHECK(cudaMalloc((void **)&d_dS, size_I * sizeof(float)));
    CUDA_CHECK(cudaMalloc((void **)&d_dW, size_I * sizeof(float)));
    CUDA_CHECK(cudaMalloc((void **)&d_dE, size_I * sizeof(float)));

    CUDA_CHECK(cudaMemcpy(d_J, J, size_I * sizeof(float), cudaMemcpyHostToDevice));

    printf("Start the SRAD main loop\n");

#ifdef ITERATION
    for (iter = 0; iter < niter; iter++) {
#endif
        sum = 0.0f;
        sum2 = 0.0f;
        for (i = r1; i <= r2; i++) {
            for (j = c1; j <= c2; j++) {
                tmp = J[i * cols + j];
                sum += tmp;
                sum2 += tmp * tmp;
            }
        }
        meanROI = sum / size_R;
        varROI = (sum2 / size_R) - meanROI * meanROI;
        q0sqr = varROI / (meanROI * meanROI);

        dim3 block(BLOCK_SIZE, BLOCK_SIZE);
        dim3 grid((cols + block.x - 1) / block.x, (rows + block.y - 1) / block.y);

        srad_cuda_1<<<grid, block>>>(d_J, d_dN, d_dS, d_dW, d_dE, d_c, rows, cols, q0sqr);
        CUDA_CHECK(cudaGetLastError());

        srad_cuda_2<<<grid, block>>>(d_J, d_c, d_dN, d_dS, d_dW, d_dE, rows, cols, lambda);
        CUDA_CHECK(cudaGetLastError());

        CUDA_CHECK(cudaDeviceSynchronize());
        CUDA_CHECK(cudaMemcpy(J, d_J, size_I * sizeof(float), cudaMemcpyDeviceToHost));
#ifdef ITERATION
    }
#endif

#ifdef OUTPUT
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            printf("%.5f ", J[i * cols + j]);
        }
        printf("\n");
    }
#endif

    printf("Computation Done\n");

    CUDA_CHECK(cudaFree(d_J));
    CUDA_CHECK(cudaFree(d_c));
    CUDA_CHECK(cudaFree(d_dN));
    CUDA_CHECK(cudaFree(d_dS));
    CUDA_CHECK(cudaFree(d_dW));
    CUDA_CHECK(cudaFree(d_dE));

    free(I);
    free(J);

    return 0;
}

